const messages = $input.all();

if (messages.length === 0) {
  return [{ json: { skip: true, reason: 'No hay mensajes hoy' } }];
}

const fechaDelDia = messages[0].json.fecha_envio;

let consolidatedText = `MENSAJES DEL DÍA ${fechaDelDia}:\n\n`;

messages.forEach((item, index) => {
  const msg = item.json;
  consolidatedText += `[${msg.hora_envio}] ${msg.sender_name}: ${msg.mensaje_texto}\n`;
});

return [{
  json: {
    skip: false,
    totalMessages: messages.length,
    consolidatedText: consolidatedText,
    fecha: fechaDelDia
  }
}];

const agentOutput = $input.first().json.output;
const fecha = $('Consolidar Mensajes1').first().json.fecha;

let parsedData;
try {
  let cleanedOutput = agentOutput;

  if (typeof cleanedOutput === 'string') {
    // Remover markdown code blocks
    cleanedOutput = cleanedOutput.replace(/```json\s*/gi, '');
    cleanedOutput = cleanedOutput.replace(/```\s*/g, '');
    cleanedOutput = cleanedOutput.trim();

    // Buscar el JSON object
    const jsonStart = cleanedOutput.indexOf('{');
    const jsonEnd = cleanedOutput.lastIndexOf('}');

    if (jsonStart !== -1 && jsonEnd !== -1) {
      cleanedOutput = cleanedOutput.substring(jsonStart, jsonEnd + 1);
    }

    // FIX PRINCIPAL: Escapar newlines reales dentro de strings JSON
    // Reemplaza newlines literales que están DENTRO de valores string
    cleanedOutput = cleanedOutput.replace(/\r\n/g, '\\n');
    cleanedOutput = cleanedOutput.replace(/\r/g, '\\n');
    cleanedOutput = cleanedOutput.replace(/\n/g, '\\n');
    // Tabs
    cleanedOutput = cleanedOutput.replace(/\t/g, '\\t');

    // Fix: doble-escape (si ya venía escapado, ahora tiene \\\\n)
    cleanedOutput = cleanedOutput.replace(/\\\\n/g, '\\n');
    cleanedOutput = cleanedOutput.replace(/\\\\t/g, '\\t');

    parsedData = JSON.parse(cleanedOutput);
  } else {
    parsedData = cleanedOutput;
  }
} catch (e) {
  // PLAN B: Extraer campos individualmente con regex
  console.error('JSON.parse falló, usando regex fallback:', e.message);

  const raw = agentOutput || '';

  // Extraer asignaciones (el array JSON)
  let asignaciones = [];
  try {
    const asigMatch = raw.match(/"asignaciones"\s*:\s*(\[[\s\S]*?\])\s*,\s*"resumen/);
    if (asigMatch) {
      // Limpiar el array antes de parsear
      let arrStr = asigMatch[1].replace(/\n/g, '').replace(/\r/g, '');
      asignaciones = JSON.parse(arrStr);
    }
  } catch (e2) {
    console.error('No se pudieron extraer asignaciones:', e2.message);
  }

  // Extraer resumen_completo como texto plano
  let resumenCompleto = 'Sin resumen';
  const rcMatch = raw.match(/"resumen_completo"\s*:\s*"([\s\S]*?)"\s*,\s*"resumen_corto/);
  if (rcMatch) {
    resumenCompleto = rcMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
  }

  // Extraer resumen_corto
  let resumenCorto = 'Sin resumen';
  const rsMatch = raw.match(/"resumen_corto"\s*:\s*"([\s\S]*?)"\s*,\s*"agenda/);
  if (rsMatch) {
    resumenCorto = rsMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
  }

  // Extraer agenda
  let agenda = '';
  const agMatch = raw.match(/"agenda_formateada"\s*:\s*"([\s\S]*?)"\s*\}/);
  if (agMatch) {
    agenda = agMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
  }

  parsedData = {
    asignaciones: asignaciones,
    resumen_completo: resumenCompleto,
    resumen_corto: resumenCorto,
    agenda_formateada: agenda
  };
}

const asignaciones = parsedData.asignaciones || [];
const resumenCompleto = parsedData.resumen_completo || 'Sin resumen';
const resumenCorto = parsedData.resumen_corto || 'Sin resumen';
const agendaFormateada = parsedData.agenda_formateada || '';

return [{
  json: {
    fecha_proceso: fecha,
    asignaciones: asignaciones,
    resumen_completo: resumenCompleto,
    resumen_corto: resumenCorto,
    agenda_formateada: agendaFormateada,
    total_asignaciones: asignaciones.length
  }
}];

const data = $input.first().json;
const asignaciones = data.asignaciones || [];

if (asignaciones.length === 0) {
  return [{ json: { skip: true } }];
}

return asignaciones.map(asig => ({
  json: {
    fecha_servicio: asig.fecha_servicio,
    propiedad: asig.propiedad,
    tipo_servicio: asig.tipo_servicio,
    limpiador: asig.limpiador || null,
    notas: asig.notas || null
  }
}));

const data = $('Parsear Output AI1').first().json;
const groupId = '120363418355921872@g.us';

const resumenCorto = data.resumen_corto.replace(/\\n/g, '\n');
const agenda = data.agenda_formateada.replace(/\\n/g, '\n');
const totalAsig = data.total_asignaciones;

let mensaje = '';

mensaje += resumenCorto;
mensaje += '\n\n━━━━━━━━━━━━━━━━━━━━\n\n';

if (agenda) {
  mensaje += agenda;
}

if (totalAsig > 0) {
  mensaje += `\n\n💾 ${totalAsig} asignación(es) guardada(s)`;
}

return [{
  json: {
    groupId: groupId,
    messageText: mensaje,
    resumen_completo: data.resumen_completo,
    agenda_completa: data.agenda_formateada,
    fecha: data.fecha_proceso,
    total_asignaciones: totalAsig
  }
}];

// Preparar documento para Qdrant con metadatos
const data = $('Preparar Resumen1').first().json;

// Extraer fecha limpia
let fecha = data.fecha;
if (fecha && fecha.includes('T')) {
  fecha = fecha.split('T')[0];
}

// Calcular día de la semana
const diasSemana = ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'];
const fechaObj = new Date(fecha + 'T12:00:00');
const diaSemana = diasSemana[fechaObj.getDay()];

// Extraer propiedades mencionadas del resumen
const resumen = data.resumen_completo || '';
const propiedadesMencionadas = [];
const limpiadoresMencionados = [];

// Lista de propiedades conocidas para detectar
const propiedadesConocidas = ['Basset', 'Basil', 'Nona', 'Bachi', 'Wells', 'Chapel', 'Voyager', 'Ivory', 'Maple', 'Rosemary', 'Westfield', 'Quail', 'Silver', 'Melba', 'Zend', 'Redcross', 'Grover', 'George', 'Turret'];

// Lista de limpiadores conocidos
const limpiadoresConocidos = ['Adriana', 'Elizabeth', 'Herminia', 'Francisca', 'Jennifer', 'Yazmin', 'Elvira', 'Lucas', 'Valentina', 'Carolina', 'Camila', 'Rosa', 'Reyna', 'Linda'];

// Detectar propiedades mencionadas
propiedadesConocidas.forEach(prop => {
  if (resumen.toLowerCase().includes(prop.toLowerCase())) {
    propiedadesMencionadas.push(prop);
  }
});

// Detectar limpiadores mencionados
limpiadoresConocidos.forEach(limp => {
  if (resumen.toLowerCase().includes(limp.toLowerCase())) {
    limpiadoresMencionados.push(limp);
  }
});

// Detectar si tiene incidencias
const tieneIncidencias = resumen.includes('⚠️') || resumen.toLowerCase().includes('incidencia') || resumen.toLowerCase().includes('problema') || resumen.toLowerCase().includes('faltante');

// Crear texto enriquecido para vectorizar
const textoParaVectorizar = `FECHA: ${fecha} (${diaSemana})\n\n${data.resumen_completo}\n\nPROPIEDADES DEL DÍA: ${propiedadesMencionadas.join(', ')}\nLIMPIADORES DEL DÍA: ${limpiadoresMencionados.join(', ')}\nTOTAL ASIGNACIONES: ${data.total_asignaciones}`;

return [{
  json: {
    text: textoParaVectorizar,
    metadata: {
      fecha: fecha,
      dia_semana: diaSemana,
      propiedades: propiedadesMencionadas.join(', '),
      limpiadores: limpiadoresMencionados.join(', '),
      tiene_incidencias: tieneIncidencias
    }
  }
}];
